<?php

declare(strict_types=1);
namespace App\Services\StudentAffairs;
use App\Enums\EnrollmentStatus; use App\Enums\StudentStatus; use App\Models\Classroom; use App\Models\Student; use App\Models\StudentEnrollment; use App\Services\ActivityLogger; use Illuminate\Support\Facades\DB; use Illuminate\Validation\ValidationException;
class EnrollmentService { public function __construct(private ActivityLogger $logger) {} public function enroll(array $data): StudentEnrollment { return DB::transaction(function() use($data){ $student=Student::findOrFail($data['student_id']); if($student->student_status instanceof StudentStatus && $student->student_status->blocksActiveEnrollment()) throw ValidationException::withMessages(['student_id'=>'Siswa dengan status nonaktif tidak dapat ditempatkan aktif.']); $classroom=Classroom::findOrFail($data['classroom_id']); if((int)$classroom->academic_year_id !== (int)$data['academic_year_id']) throw ValidationException::withMessages(['classroom_id'=>'Kelas harus sesuai tahun ajaran.']); if(StudentEnrollment::where('student_id',$student->id)->where('academic_year_id',$data['academic_year_id'])->where('enrollment_status',EnrollmentStatus::Active->value)->exists()) throw ValidationException::withMessages(['student_id'=>'Siswa sudah memiliki penempatan aktif pada tahun ajaran ini.']); if($classroom->capacity && StudentEnrollment::where('classroom_id',$classroom->id)->where('enrollment_status',EnrollmentStatus::Active->value)->count() >= $classroom->capacity) throw ValidationException::withMessages(['classroom_id'=>'Kapasitas kelas sudah penuh.']); $enrollment=StudentEnrollment::create($data+['enrollment_status'=>EnrollmentStatus::Active,'enrolled_at'=>$data['enrolled_at']??now()->toDateString()]); $this->logger->log('student.enrolled',$enrollment,[],$enrollment->getAttributes(),'Siswa ditempatkan ke kelas.'); return $enrollment; }); } public function transfer(StudentEnrollment $current, int $classroomId, ?string $notes=null): StudentEnrollment { return DB::transaction(function() use($current,$classroomId,$notes){ $current->update(['enrollment_status'=>EnrollmentStatus::Transferred,'completed_at'=>now()->toDateString(),'notes'=>$notes]); return $this->enroll(['student_id'=>$current->student_id,'academic_year_id'=>$current->academic_year_id,'classroom_id'=>$classroomId,'notes'=>$notes]); }); } }
